requests.testScript:
pw.env.set("TEST_ORDER", "target-req");
pw.env.set("ORDER_AT_REQ", pw.env.get("TEST_ORDER"));
pw.test("pre-script cascade ran in root->target-folder->target-req order", () => {
  pw.expect(pw.env.get("PRE_ORDER")).toBe("root->target-folder->target-req");
});
pw.test("all cascade pre-scripts committed env vars", () => {
  pw.expect(pw.env.get("ROOT_RAN")).toBe("yes");
  pw.expect(pw.env.get("TARGET_FOLDER_RAN")).toBe("yes");
  pw.expect(pw.env.get("REQ_RAN")).toBe("yes");
});
pw.test("request-level test observed request position in test-cascade", () => {
  pw.expect(pw.env.get("ORDER_AT_REQ")).toBe("target-req");
});

pw.env.set("TEST_ORDER", "sibling-req-in-target");
pw.test("sibling request cascade is root->target-folder->this-request", () => {
  pw.expect(pw.env.get("PRE_ORDER")).toBe("root->target-folder->sibling-req-in-target");
});

pw.env.set("TEST_ORDER", "sibling-req-in-sibling");
pw.test("sibling-folder cascade is root->sibling-folder->this-request (no target-folder leak)", () => {
  pw.expect(pw.env.get("PRE_ORDER")).toBe("root->sibling-folder->sibling-req-in-sibling");
});
pw.test("target-folder pre-script ran exactly twice (one per request in target-folder)", () => {
  pw.expect(pw.env.get("TARGET_FOLDER_RUN_COUNT")).toBe("2");
});

testScript:
pw.env.set("TEST_ORDER", pw.env.get("TEST_ORDER") + "->root");
pw.test("test-script cascade ran in request->folder->root order for every request", () => {
  pw.expect(["target-req->target-folder->root", "sibling-req-in-target->target-folder->root", "sibling-req-in-sibling->sibling-folder->root"].includes(pw.env.get("TEST_ORDER"))).toBe(true);
});
